{ (void)gtm; mock_IfxGtm_enable_callCount++; }

void IfxGtm_Pwm_initConfig(IfxGtm_Pwm_Config *config, Ifx_GTM *gtmSFR)
{ (void)gtmSFR; mock_IfxGtm_Pwm_initConfig_callCount++; if (config != NULL_PTR) { mock_IfxGtm_Pwm_initConfig_lastNumChannels = config->numChannels; mock_IfxGtm_Pwm_initConfig_lastFrequency = config->frequency; } }

void IfxGtm_Pwm_init(IfxGtm_Pwm *pwm, IfxGtm_Pwm_Channel *channels, IfxGtm_Pwm_Config *config)
{ (void)pwm; (void)channels; mock_IfxGtm_Pwm_init_callCount++; if (config != NULL_PTR) { mock_IfxGtm_Pwm_init_lastNumChannels = config->numChannels; mock_IfxGtm_Pwm_init_lastFrequency = config->frequency; _captured_numChannels = config->numChannels; } else { _captured_numChannels = 0; } }

void IfxGtm_Pwm_updateChannelsDutyImmediate(IfxGtm_Pwm *pwm, float32 *requestDuty)
{ (void)pwm; mock_IfxGtm_Pwm_updateChannelsDutyImmediate_callCount++; uint32 n = (_captured_numChannels > 0U && _captured_numChannels <= (uint32)MOCK_MAX_CHANNELS) ? _captured_numChannels : (uint32)MOCK_MAX_CHANNELS; for (uint32 i = 0; i < n; ++i) { mock_IfxGtm_Pwm_updateChannelsDutyImmediate_lastDuties[i] = (requestDuty != NULL_PTR) ? requestDuty[i] : 0.0f; } }

IfxGtm_Pwm_ChannelState IfxGtm_Pwm_getChannelState(IfxGtm_Pwm *pwm, IfxGtm_Pwm_SubModule_Ch ch)
{ (void)pwm; (void)ch; mock_IfxGtm_Pwm_getChannelState_callCount++; return (IfxGtm_Pwm_ChannelState)mock_IfxGtm_Pwm_getChannelState_returnValue; }

/* Getters */
